import React, { useEffect, useState } from 'react';

import { api } from '../api/api';

interface VacanciesPageProps {
    onRequest?: () => void;
}

interface Vacancy {
    id: number;
    title: string;
    description: string;
    salary: string;
    requirements: string;
}

const VacanciesPage: React.FC<VacanciesPageProps> = ({ onRequest }) => {
    const [vacancies, setVacancies] = useState<Vacancy[]>([]);
    const [loading, setLoading] = useState<boolean>(true);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        api.getVacancies()
            .then(data => {
                setVacancies(data);
                setLoading(false);
            })
            .catch(err => {
                console.error(err);
                setError('Не удалось загрузить вакансии');
                setLoading(false);
            });
    }, []);

    if (loading) return <div className="page-shell text-center font-semibold text-graphite-500">Загрузка вакансий...</div>;

    if (error) return <div className="page-shell text-center font-semibold text-red-600">{error}</div>;

    return (
        <div className="container mx-auto px-4 py-8">
            <h1 className="text-4xl font-bold mb-8 text-center">Вакансии</h1>
            <div className="space-y-6">
                {vacancies.map((vacancy, index) => (
                    <div key={index} className="bg-white rounded-lg shadow-md p-6 border-l-4 border-green-500 hover:shadow-lg transition">
                        <h3 className="text-2xl font-semibold text-gray-800">{vacancy.title}</h3>
                        <div className="mt-3">
                            <h4 className="font-semibold">Требования:</h4>
                            <ul className="list-disc list-inside text-gray-700">
                                {vacancy.requirements.map((req, i) => (
                                    <li key={i}>{req}</li>
                                ))}
                            </ul>
                        </div>
                        <div className="mt-3">
                            <h4 className="font-semibold">Обязанности:</h4>
                            <ul className="list-disc list-inside text-gray-700">
                                {vacancy.responsibilities.map((resp, i) => (
                                    <li key={i}>{resp}</li>
                                ))}
                            </ul>
                        </div>
                        <div className="mt-3 text-sm">
                            <span className="font-semibold">По вопросам по вакансии:</span>
                            <a
                                href={`tel:${vacancy.contactPhone.replace(/[^+\d]/g, '')}`}
                                className="ml-2 text-blue-600 hover:underline"
                            >
                                {vacancy.contactPhone}
                            </a>
                            <a href={`mailto:${vacancy.contactEmail}`} className="ml-2 text-blue-600 hover:underline">
                                {vacancy.contactEmail}
                            </a>
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
};

export default VacanciesPage;
